@@ -0,0 +1,6531 @@
+/* Import Google Fonts - Playfair Display + Jost */
+@import url('https://fonts.googleapis.com/css2?family=Playfair+Display:wght@400;500;600;700&family=Jost:wght@300;400;500;600&display=swap');
+
+@import "tailwindcss";
+
+@theme {
+  /* Aromaz Brand Colors - Mediterranean Warmth Palette */
+  --color-cream: #F9F4EE;
+  --color-clay: #D4C4B0;
+  --color-olive: #6B7F5F;
+  --color-lavender: #9B8FB5;
+  --color-rose-gold: #D4A59A;
+  --color-terracotta: #B2441E;
+  --color-sage: #132805;
+  --color-amber: #C4936B;
+  --color-charcoal: #202322;
+  --color-seafoam: #9ab8b5;
+  --color-mist: #cfe0e1;
+  --color-linen: #E8E3DC;
+  --color-off-white: #FDFCFA;
+
+  /* Typography - Premium Serif + Modern Sans (from aesthetic research) */
+  --font-serif: "Playfair Display", Georgia, serif;
+  --font-sans: "Jost", "Inter", system-ui, sans-serif;
+
+  /*
+   * Z-Index Layer Scale
+   * See: lore/clean_code/z-index-management.md
+   *
+   * Layer 0: Base (use default z-0 to z-50)
+   * Layer 1: Sticky elements (headers, footers, CTAs)
+   * Layer 2: Dropdowns (menus, popovers)
+   * Layer 3: Drawers (cart, mobile menu, search)
+   * Layer 4: Modals (dialogs, confirmations)
+   * Layer 5: Toasts (notifications, alerts)
+   */
+  --z-index-sticky: 100;
+  --z-index-dropdown: 300;
+  --z-index-drawer: 400;
+  --z-index-modal: 500;
+  --z-index-toast: 600;
+
+  /* Legacy variables for existing components */
+  --aside-width: 400px;
+  --cart-aside-summary-height-with-discount: 300px;
+  --cart-aside-summary-height: 250px;
+  --grid-item-width: 355px;
+  --header-height: 64px;
+  --color-dark: var(--color-charcoal);
+  --color-light: var(--color-off-white);
+}
+
+img {
+  border-radius: 4px;
+}
+
+/*
+* --------------------------------------------------
+* Non anchor links
+* --------------------------------------------------
+*/
+.link:hover {
+  text-decoration: underline;
+  cursor: pointer;
+}
+
+/*
+* --------------------------------------------------
+* components/Aside
+* --------------------------------------------------
+*/
+@media (max-width: 45em) {
+  html:has(.overlay.expanded) {
+    overflow: hidden;
+  }
+}
+
+aside {
+  background: var(--color-light);
+  box-shadow: 0 0 50px rgba(0, 0, 0, 0.3);
+  /* iOS Safari fix: Use svh (small viewport height) to account for browser toolbar */
+  /* svh = viewport height when browser UI is maximally expanded (toolbar visible) */
+  /* This prevents bottom fixed elements from being hidden behind Safari's toolbar */
+  height: 100vh; /* Fallback for older browsers */
+  height: 100svh; /* Small viewport height - Safari 15.4+, Chrome 108+ */
+  width: min(var(--aside-width), 100vw);
+  position: fixed;
+  right: calc(-1 * var(--aside-width));
+  top: 0;
+  transition: transform 200ms ease-in-out;
+}
+
+aside header {
+  align-items: center;
+  border-bottom: 1px solid var(--color-dark);
+  display: flex;
+  height: var(--header-height);
+  justify-content: space-between;
+  padding: 0 20px;
+}
+
+aside header h3 {
+  margin: 0;
+}
+
+aside header .close {
+  font-weight: bold;
+  opacity: 0.8;
+  text-decoration: none;
+  transition: all 200ms;
+  width: 20px;
+}
+
+aside header .close:hover {
+  opacity: 1;
+}
+
+aside header h2 {
+  margin-bottom: 0.6rem;
+  margin-top: 0;
+}
+
+aside main {
+  margin: 1rem;
+}
+
+aside p {
+  margin: 0 0 0.25rem;
+}
+
+aside p:last-child {
+  margin: 0;
+}
+
+aside li {
+  margin-bottom: 0.125rem;
+}
+
+.overlay {
+  background: rgba(0, 0, 0, 0.2);
+  bottom: 0;
+  left: 0;
+  opacity: 0;
+  pointer-events: none;
+  position: fixed;
+  right: 0;
+  top: 0;
+  transition: opacity 400ms ease-in-out;
+  transition: opacity 400ms;
+  visibility: hidden;
+  z-index: var(--z-index-drawer); /* Layer 3: Drawers - see lore/clean_code/z-index-management.md */
+}
+
+.overlay .close-outside {
+  background: transparent;
+  border: none;
+  color: transparent;
+  height: 100%;
+  left: 0;
+  position: absolute;
+  top: 0;
+  width: calc(100% - var(--aside-width));
+}
+
+.overlay .light {
+  background: rgba(255, 255, 255, 0.5);
+}
+
+.overlay .cancel {
+  cursor: default;
+  height: 100%;
+  position: absolute;
+  width: 100%;
+}
+
+.overlay.expanded {
+  opacity: 1;
+  pointer-events: auto;
+  visibility: visible;
+}
+/* reveal aside */
+.overlay.expanded aside {
+  transform: translateX(calc(var(--aside-width) * -1));
+}
+
+button.reset {
+  border: 0;
+  background: inherit;
+  font-size: inherit;
+}
+
+button.reset > * {
+  margin: 0;
+}
+
+button.reset:not(:has(> *)) {
+  height: 1.5rem;
+  line-height: 1.5rem;
+}
+
+button.reset:hover:not(:has(> *)) {
+  text-decoration: underline;
+  cursor: pointer;
+}
+
+/*
+* --------------------------------------------------
+* components/Header
+* --------------------------------------------------
+*/
+.header {
+  align-items: center;
+  background: #fff;
+  display: flex;
+  height: var(--header-height);
+  padding: 0 1rem;
+  position: sticky;
+  top: 0;
+  z-index: 50;
+}
+
+.header-menu-mobile-toggle {
+  @media (min-width: 48em) {
+    display: none;
+  }
+}
+
+.header-menu-mobile {
+  display: flex;
+  flex-direction: column;
+  grid-gap: 1rem;
+}
+
+.header-menu-desktop {
+  display: none;
+  grid-gap: 1rem;
+  @media (min-width: 45em) {
+    display: flex;
+    grid-gap: 1rem;
+    margin-left: 3rem;
+  }
+}
+
+.header-menu-item {
+  cursor: pointer;
+}
+
+.header-ctas {
+  align-items: center;
+  display: flex;
+  grid-gap: 1rem;
+  margin-left: auto;
+}
+
+.header-ctas > * {
+  min-width: fit-content;
+}
+
+/*
+* --------------------------------------------------
+* components/Footer
+* --------------------------------------------------
+*/
+.footer {
+  background: var(--color-dark);
+  margin-top: auto;
+}
+
+.footer-menu {
+  justify-content: center;
+  display: flex;
+  flex-wrap: wrap;
+  grid-gap: 1rem;
+  padding: 1rem;
+}
+
+.footer-menu a {
+  color: var(--color-light);
+  min-width: fit-content;
+}
+
+/*
+* --------------------------------------------------
+* components/Cart
+* --------------------------------------------------
+*/
+.cart-main {
+  height: 100%;
+  max-height: calc(100vh - var(--cart-aside-summary-height)); /* Fallback */
+  max-height: calc(100svh - var(--cart-aside-summary-height)); /* iOS Safari */
+  overflow-y: auto;
+  width: auto;
+}
+
+.cart-main.with-discount {
+  max-height: calc(100vh - var(--cart-aside-summary-height-with-discount)); /* Fallback */
+  max-height: calc(100svh - var(--cart-aside-summary-height-with-discount)); /* iOS Safari */
+}
+
+.cart-line {
+  display: flex;
+  padding: 0.75rem 0;
+}
+
+.cart-line img {
+  height: 100%;
+  display: block;
+  margin-right: 0.75rem;
+}
+
+.cart-summary-page {
+  position: relative;
+}
+
+.cart-summary-aside {
+  background: white;
+  border-top: 1px solid var(--color-dark);
+  bottom: 0;
+  padding-top: 0.75rem;
+  position: absolute;
+  width: calc(var(--aside-width) - 40px);
+}
+
+.cart-line-quantity {
+  display: flex;
+}
+
+.cart-discount {
+  align-items: center;
+  display: flex;
+  margin-top: 0.25rem;
+}
+
+.cart-subtotal {
+  align-items: center;
+  display: flex;
+}
+
+.cart-empty-action {
+  align-items: center;
+  background: var(--color-charcoal);
+  border: 1px solid var(--color-charcoal);
+  border-radius: 6px;
+  color: var(--color-cream);
+  display: inline-flex;
+  font-family: var(--font-sans);
+  font-size: 0.84rem;
+  font-weight: 700;
+  justify-content: center;
+  letter-spacing: 0.12em;
+  min-height: 46px;
+  padding: 0 1.25rem;
+  text-transform: uppercase;
+  transition:
+    background-color 160ms ease,
+    border-color 160ms ease,
+    color 160ms ease;
+}
+
+.cart-empty-action:hover {
+  background: var(--color-terracotta);
+  border-color: var(--color-terracotta);
+  color: var(--color-cream);
+  text-decoration: none;
+}
+
+.cart-summary-page a {
+  align-items: center;
+  background: var(--color-charcoal);
+  border-radius: 6px;
+  color: var(--color-cream);
+  display: inline-flex;
+  font-size: 0.78rem;
+  font-weight: 700;
+  justify-content: center;
+  letter-spacing: 0.12em;
+  min-height: 46px;
+  padding: 0 1.1rem;
+  text-transform: uppercase;
+  transition:
+    background-color 160ms ease,
+    color 160ms ease;
+}
+
+.cart-summary-page a:hover {
+  background: var(--color-terracotta);
+  color: var(--color-cream);
+}
+
+.cart-summary-page a p {
+  color: inherit;
+  margin: 0;
+}
+
+.cart-summary-page a,
+.cart-checkout-button {
+  background: #566d37 !important;
+  border: 1px solid #566d37 !important;
+  border-radius: 999px !important;
+  box-shadow: 0 14px 32px rgba(86, 109, 55, 0.24) !important;
+  color: var(--color-off-white) !important;
+}
+
+.cart-summary-page a:hover,
+.cart-checkout-button:hover {
+  background: #7f936d !important;
+  border-color: #7f936d !important;
+  color: var(--color-off-white) !important;
+  text-decoration: none;
+}
+/*
+* --------------------------------------------------
+* components/Search
+* --------------------------------------------------
+*/
+.predictive-search {
+  height: calc(100vh - var(--header-height) - 40px); /* Fallback */
+  height: calc(100svh - var(--header-height) - 40px); /* iOS Safari */
+  overflow-y: auto;
+}
+
+.predictive-search-form {
+  background: var(--color-light);
+  position: sticky;
+  top: 0;
+}
+
+.predictive-search-result {
+  margin-bottom: 2rem;
+}
+
+.predictive-search-result h5 {
+  text-transform: uppercase;
+}
+
+.predictive-search-result-item {
+  margin-bottom: 0.5rem;
+}
+
+.predictive-search-result-item a {
+  align-items: center;
+  display: flex;
+}
+
+.predictive-search-result-item a img {
+  margin-right: 0.75rem;
+  height: 100%;
+}
+
+.search-result {
+  margin-bottom: 1.5rem;
+}
+
+.search-results-item {
+  margin-bottom: 0.5rem;
+}
+
+.search-results-item a {
+  display: flex;
+  flex: row;
+  align-items: center;
+  gap: 1rem;
+}
+
+/*
+* --------------------------------------------------
+* routes/__index
+* --------------------------------------------------
+*/
+.featured-collection {
+  display: block;
+  margin-bottom: 2rem;
+  position: relative;
+}
+
+.featured-collection-image {
+  aspect-ratio: 1 / 1;
+  @media (min-width: 45em) {
+    aspect-ratio: 16 / 9;
+  }
+}
+
+.featured-collection img {
+  height: auto;
+  max-height: 100%;
+  object-fit: cover;
+}
+
+.recommended-products-grid {
+  display: grid;
+  grid-gap: 1.5rem;
+  grid-template-columns: repeat(2, 1fr);
+  @media (min-width: 45em) {
+    grid-template-columns: repeat(4, 1fr);
+  }
+}
+
+.recommended-product img {
+  height: auto;
+}
+
+/*
+* --------------------------------------------------
+* routes/collections._index.tsx
+* --------------------------------------------------
+*/
+.collections-grid {
+  display: grid;
+  grid-gap: 1.5rem;
+  grid-template-columns: repeat(auto-fit, minmax(var(--grid-item-width), 1fr));
+  margin-bottom: 2rem;
+}
+
+.collection-item img {
+  height: auto;
+}
+
+/*
+* --------------------------------------------------
+* routes/collections.$handle.tsx
+* --------------------------------------------------
+*/
+.collection-description {
+  margin-bottom: 1rem;
+  max-width: 95%;
+  @media (min-width: 45em) {
+    max-width: 600px;
+  }
+}
+
+.products-grid {
+  display: grid;
+  grid-gap: 1.5rem;
+  grid-template-columns: repeat(auto-fit, minmax(var(--grid-item-width), 1fr));
+  margin-bottom: 2rem;
+}
+
+.product-item img {
+  height: auto;
+  width: 100%;
+}
+
+/*
+* --------------------------------------------------
+* routes/products.$handle.tsx
+* --------------------------------------------------
+*/
+.product {
+  display: grid;
+  @media (min-width: 45em) {
+    grid-template-columns: 1fr 1fr;
+    grid-gap: 4rem;
+  }
+}
+
+.product h1 {
+  margin-top: 0;
+}
+
+.product-image img {
+  height: auto;
+  width: 100%;
+}
+
+.product-main {
+  align-self: start;
+  position: sticky;
+  top: 6rem;
+}
+
+.product-price-on-sale {
+  display: flex;
+  grid-gap: 0.5rem;
+}
+
+.product-price-on-sale s {
+  opacity: 0.5;
+}
+
+.product-options-grid {
+  display: flex;
+  flex-wrap: wrap;
+  grid-gap: 0.75rem;
+}
+
+.product-options-item,
+.product-options-item:disabled {
+  padding: 0.25rem 0.5rem;
+  background-color: transparent;
+  font-size: 1rem;
+  font-family: inherit;
+}
+
+.product-option-label-swatch {
+  width: 1.25rem;
+  height: 1.25rem;
+  margin: 0.25rem 0;
+}
+
+.product-option-label-swatch img {
+  width: 100%;
+}
+
+/*
+* --------------------------------------------------
+* routes/blog._index.tsx
+* --------------------------------------------------
+*/
+.blog-grid {
+  display: grid;
+  grid-gap: 1.5rem;
+  grid-template-columns: repeat(auto-fit, minmax(var(--grid-item-width), 1fr));
+  margin-bottom: 2rem;
+}
+
+.blog-article-image {
+  aspect-ratio: 3/2;
+  display: block;
+}
+
+.blog-article-image img {
+  height: 100%;
+}
+
+/*
+* --------------------------------------------------
+* routes/blog.$articlehandle.tsx
+* --------------------------------------------------
+*/
+.article img {
+  height: auto;
+  width: 100%;
+}
+
+/*
+* --------------------------------------------------
+* routes/account
+* --------------------------------------------------
+*/
+
+.account-logout {
+  display: inline-block;
+}
+
+/*
+* --------------------------------------------------
+* Order Search Form - Minimal & Responsive
+* --------------------------------------------------
+*/
+.order-search-form {
+  margin-bottom: 1.5rem;
+}
+
+.order-search-fieldset {
+  border: 1px solid #e5e5e5;
+  border-radius: 4px;
+  padding: 1rem;
+}
+
+.order-search-legend {
+  font-weight: 600;
+  padding: 0 0.5rem;
+}
+
+.order-search-active {
+  font-weight: normal;
+  opacity: 0.7;
+  margin-left: 0.5rem;
+}
+
+.order-search-inputs {
+  display: grid;
+  gap: 1rem;
+  margin: 0.25rem 0 1rem;
+  grid-template-columns: 1fr;
+}
+
+@media (min-width: 640px) {
+  .order-search-inputs {
+    grid-template-columns: 1fr 1fr;
+  }
+}
+
+.order-search-input {
+  width: 100%;
+  padding: 0.5rem;
+  border: 1px solid #d1d5db;
+  border-radius: 4px;
+  font-size: 1rem;
+}
+
+.order-search-buttons {
+  display: flex;
+  gap: 0.75rem;
+  flex-wrap: wrap;
+}
+
+/*
+* --------------------------------------------------
+* Subscription Management
+* --------------------------------------------------
+*/
+
+.account-subscriptions h2 {
+  font-size: 1.25rem;
+  font-weight: 600;
+  margin-bottom: 1rem;
+  color: #3A3A3A;
+}
+
+.account-subscriptions section + section {
+  margin-top: 2.5rem;
+}
+
+.subscription-list {
+  display: flex;
+  flex-direction: column;
+  gap: 1rem;
+}
+
+.subscription-card {
+  border: 1px solid #D4C4B0;
+  border-radius: 8px;
+  padding: 1.25rem;
+  background: #FDFCFA;
+}
+
+.subscription-card-header {
+  display: flex;
+  justify-content: space-between;
+  align-items: center;
+  margin-bottom: 0.75rem;
+  flex-wrap: wrap;
+  gap: 0.5rem;
+}
+
+.subscription-status {
+  display: inline-block;
+  padding: 0.25rem 0.75rem;
+  border-radius: 9999px;
+  font-size: 0.75rem;
+  font-weight: 600;
+  text-transform: uppercase;
+  letter-spacing: 0.05em;
+}
+
+.subscription-status-active {
+  background: #e8f0e4;
+  color: #4a6741;
+}
+
+.subscription-status-paused {
+  background: #fef3e2;
+  color: #92600a;
+}
+
+.subscription-status-cancelled {
+  background: #f0eded;
+  color: #6b6b6b;
+}
+
+.subscription-status-expired {
+  background: #f0eded;
+  color: #6b6b6b;
+}
+
+.subscription-status-failed {
+  background: #fde8e8;
+  color: #9b2c2c;
+}
+
+.subscription-next-date {
+  font-size: 0.875rem;
+  color: #6b6b6b;
+}
+
+.subscription-card-body {
+  display: flex;
+  flex-direction: column;
+  gap: 0.5rem;
+}
+
+.subscription-line {
+  display: flex;
+  justify-content: space-between;
+  align-items: baseline;
+  flex-wrap: wrap;
+  gap: 0.25rem;
+}
+
+.subscription-line-name {
+  font-weight: 500;
+  color: #3A3A3A;
+}
+
+.subscription-line-details {
+  font-size: 0.875rem;
+  color: #6b6b6b;
+}
+
+.subscription-frequency {
+  font-size: 0.875rem;
+  color: #6B7F5F;
+  font-weight: 500;
+  margin-top: 0.25rem;
+}
+
+.subscription-discounts {
+  display: flex;
+  gap: 0.5rem;
+  flex-wrap: wrap;
+  margin-top: 0.25rem;
+}
+
+.subscription-discount-badge {
+  display: inline-block;
+  padding: 0.125rem 0.5rem;
+  border-radius: 4px;
+  font-size: 0.75rem;
+  background: #e8f0e4;
+  color: #4a6741;
+}
+
+.subscription-meta {
+  font-size: 0.8125rem;
+  color: #9b9b9b;
+  margin-top: 0.25rem;
+}
+
+.subscription-card-actions {
+  display: flex;
+  gap: 0.75rem;
+  margin-top: 1rem;
+  padding-top: 1rem;
+  border-top: 1px solid #E8E3DC;
+  flex-wrap: wrap;
+}
+
+.subscription-btn {
+  padding: 0.5rem 1.25rem;
+  border-radius: 6px;
+  font-size: 0.875rem;
+  font-weight: 500;
+  cursor: pointer;
+  border: 1px solid transparent;
+  min-height: 44px;
+  min-width: 44px;
+  transition: background-color 0.15s ease;
+}
+
+.subscription-btn-primary {
+  background: #6B7F5F;
+  color: #fff;
+  border-color: #6B7F5F;
+}
+
+.subscription-btn-primary:hover {
+  background: #5a6e50;
+}
+
+.subscription-btn-secondary {
+  background: #F8F5F0;
+  color: #3A3A3A;
+  border-color: #D4C4B0;
+}
+
+.subscription-btn-secondary:hover {
+  background: #E8E3DC;
+}
+
+.subscription-btn-danger {
+  background: transparent;
+  color: #9b2c2c;
+  border-color: #e8c4c4;
+}
+
+.subscription-btn-danger:hover {
+  background: #fde8e8;
+}
+
+.subscription-card-footer {
+  margin-top: 1rem;
+  padding-top: 0.75rem;
+  border-top: 1px solid #E8E3DC;
+}
+
+.subscription-ended {
+  font-size: 0.8125rem;
+  color: #9b9b9b;
+}
+
+.subscription-empty {
+  text-align: center;
+  padding: 2rem 1rem;
+  color: #6b6b6b;
+}
+
+.subscription-error {
+  padding: 0.75rem 1rem;
+  border-radius: 6px;
+  background: #fde8e8;
+  color: #9b2c2c;
+  border: 1px solid #e8c4c4;
+  margin-bottom: 1rem;
+  font-size: 0.875rem;
+}
+
+.subscription-success {
+  padding: 0.75rem 1rem;
+  border-radius: 6px;
+  background: #e8f0e4;
+  color: #4a6741;
+  border: 1px solid #c4d6be;
+  margin-bottom: 1rem;
+  font-size: 0.875rem;
+}
+
+/*
+* --------------------------------------------------
+* Aromaz Clean Premium Refresh
+* --------------------------------------------------
+*/
+html {
+  background: var(--color-cream);
+  color: var(--color-charcoal);
+  font-family: var(--font-sans);
+}
+
+body {
+  background: var(--color-cream);
+  color: var(--color-charcoal);
+  font-family: var(--font-sans);
+}
+
+a {
+  color: inherit;
+  text-decoration: none;
+}
