  height: 100svh;
  margin-bottom: -100svh;
  position: sticky;
  top: 0;
  transform: scale(1.04);
  transform-origin: center;
  will-change: transform, filter;
  width: 100%;
}

.catalog-panel-content {
  align-items: start;
  display: grid;
  gap: clamp(2rem, 5vw, 5rem);
  grid-template-columns: repeat(2, minmax(320px, 1fr));
  justify-items: center;
  min-height: 150svh;
  padding: clamp(5rem, 9vw, 9rem) clamp(1.5rem, 5vw, 5rem);
  position: relative;
}

.catalog-panel-product {
  animation: catalog-product-drift linear both;
  animation-range: entry 0% exit 100%;
  animation-timeline: --catalog-panel-progress;
  display: grid;
  min-height: var(--catalog-panel-box-height);
  place-items: start center;
  position: sticky;
  top: calc(var(--header-height) + 2rem);
  width: var(--catalog-panel-box-width);
  will-change: transform;
}

.catalog-panel-product img {
  filter: drop-shadow(0 40px 70px rgba(32, 35, 34, 0.38));
  height: var(--catalog-panel-box-height);
  max-width: none;
  object-fit: cover;
  transform: none;
  width: 100%;
}

.catalog-panel-card {
  animation: catalog-card-drift linear both;
  animation-range: entry 0% exit 100%;
  animation-timeline: --catalog-panel-progress;
  align-self: start;
  backdrop-filter: blur(20px);
  background: rgba(249, 244, 238, 0.9);
  border: 1px solid rgba(249, 244, 238, 0.7);
  border-radius: 8px;
  box-sizing: border-box;
  box-shadow: 0 34px 90px rgba(32, 35, 34, 0.24);
  color: var(--color-charcoal);
  display: flex;
  flex-direction: column;
  justify-content: flex-start;
  min-height: var(--catalog-panel-box-height);
  margin-top: 0;
  max-width: none;
  padding: clamp(1.4rem, 3vw, 2.35rem);
  position: sticky;
  top: calc(var(--header-height) + 2rem);
  width: var(--catalog-panel-box-width);
  will-change: transform;
}

.catalog-panel-card > p {
  color: var(--color-terracotta);
  margin-bottom: 2rem;
}

.catalog-panel-card h2 {
  font-family: var(--font-serif);
  font-size: clamp(2.7rem, 6vw, 6.5rem);
  line-height: 0.9;
  margin: 0.7rem 0 1rem;
}

.catalog-panel-card strong {
  color: var(--color-terracotta);
  display: block;
  font-size: 1rem;
  margin-top: auto;
  margin-bottom: 1.25rem;
}

.catalog-panel-card div {
  display: grid;
  gap: 0.75rem;
}

.catalog-panel-card div p {
  color: rgba(32, 35, 34, 0.74);
  font-size: 1rem;
  line-height: 1.65;
  margin: 0;
}

.catalog-panel-card a {
  background: var(--color-terracotta);
  color: var(--color-cream);
  margin-top: 1.5rem;
}

@keyframes catalog-product-drift {
  0% {
    transform: translateY(6svh);
  }

  55% {
    transform: translateY(0);
  }

  100% {
    transform: translateY(-6svh);
  }
}

@keyframes catalog-card-drift {
  0% {
    transform: translateY(6svh);
  }

  55% {
    transform: translateY(0);
  }

  100% {
    transform: translateY(-5svh);
  }
}

@keyframes catalog-backdrop-exit {
  0% {
    filter: blur(0) saturate(1);
    transform: scale(1.04);
  }

  100% {
    filter: blur(10px) saturate(1.08);
    transform: scale(1.16);
  }
}

.brochure-catalog {
  background: var(--color-charcoal);
  color: var(--color-cream);
  overflow: clip;
}

.brochure-catalog-intro {
  display: grid;
  gap: 1rem;
  margin: 0 auto;
  max-width: 1280px;
  padding: clamp(4rem, 8vw, 7rem) clamp(1.5rem, 4vw, 4rem)
    clamp(2.5rem, 5vw, 4rem);
}

.brochure-catalog-intro p,
.parallax-product-copy span,
.parallax-product-count {
  font-family: var(--font-sans);
  font-size: 0.72rem;
  font-weight: 700;
  letter-spacing: 0.18em;
  line-height: 1.4;
  margin: 0;
  text-transform: uppercase;
}

.brochure-catalog-intro p {
  color: var(--color-clay);
}

.brochure-catalog-intro h2 {
  color: var(--color-cream);
  font-family: var(--font-serif);
  font-size: clamp(2.5rem, 8vw, 6.75rem);
  line-height: 0.96;
  margin: 0;
  max-width: 920px;
}

.brochure-catalog-intro span {
  color: rgba(249, 244, 238, 0.72);
  display: block;
  font-size: clamp(1rem, 2vw, 1.25rem);
  line-height: 1.65;
  max-width: 660px;
}

.parallax-products {
  display: grid;
}

.parallax-product {
  isolation: isolate;
  min-height: 100svh;
  overflow: hidden;
  position: relative;
}

.parallax-product::before {
  background-image:
    linear-gradient(
      90deg,
      rgba(32, 35, 34, 0.88),
      rgba(32, 35, 34, 0.42) 52%,
      rgba(32, 35, 34, 0.14)
    ),
    var(--parallax-bg);
  background-attachment: fixed;
  background-position: center;
  background-repeat: no-repeat;
  background-size: cover;
  content: "";
  inset: -4%;
  position: absolute;
  transform: scale(1.04);
  z-index: -2;
}

.parallax-product::after {
  background:
    radial-gradient(circle at 72% 40%, rgba(249, 244, 238, 0.34), transparent 34%),
    linear-gradient(180deg, rgba(249, 244, 238, 0.08), rgba(32, 35, 34, 0.38));
  content: "";
  inset: 0;
  position: absolute;
  z-index: -1;
}

.parallax-product-inner {
  align-items: center;
  display: grid;
  gap: clamp(2rem, 5vw, 5rem);
  grid-template-columns: minmax(0, 0.82fr) minmax(320px, 0.72fr);
  margin: 0 auto;
  max-width: 1280px;
  min-height: 100svh;
  padding: clamp(5rem, 8vw, 8rem) clamp(1.5rem, 4vw, 4rem);
}

.parallax-product-copy {
  backdrop-filter: blur(16px);
  background: rgba(249, 244, 238, 0.86);
  border: 1px solid rgba(249, 244, 238, 0.62);
  border-radius: 8px;
  box-shadow: 0 28px 90px rgba(32, 35, 34, 0.2);
  color: var(--color-charcoal);
  max-width: 580px;
  padding: clamp(1.5rem, 3vw, 2.25rem);
}

.parallax-product-count {
  color: var(--color-terracotta);
  margin-bottom: 2rem;
}

.parallax-product-copy span {
  color: var(--color-olive);
  display: block;
  margin-bottom: 0.8rem;
}

.parallax-product-copy h3 {
  color: var(--color-charcoal);
  font-family: var(--font-serif);
  font-size: clamp(2.5rem, 6vw, 5.75rem);
  line-height: 0.94;
  margin: 0;
}

.parallax-product-copy p:not(.parallax-product-count) {
  color: rgba(32, 35, 34, 0.74);
  font-size: clamp(1rem, 1.7vw, 1.18rem);
  line-height: 1.7;
  margin: 1.25rem 0 0;
}

.parallax-product-actions {
  align-items: center;
  border-top: 1px solid rgba(32, 35, 34, 0.12);
  display: flex;
  flex-wrap: wrap;
  gap: 1rem;
  justify-content: space-between;
  margin-top: 1.75rem;
  padding-top: 1.25rem;
}

.parallax-product-actions strong {
  color: var(--color-terracotta);
  font-family: var(--font-sans);
  font-size: 0.95rem;
  font-weight: 700;
}

.parallax-product-actions a {
  align-items: center;
  background: var(--color-charcoal);
  border-radius: 6px;
  color: var(--color-cream);
  display: inline-flex;
  font-size: 0.72rem;
  font-weight: 700;
  justify-content: center;
  letter-spacing: 0.14em;
  min-height: 44px;
  padding: 0.85rem 1.1rem;
  text-transform: uppercase;
  transition:
    background-color 160ms ease,
    transform 160ms ease;
}

.parallax-product-actions a:hover {
  background: var(--color-sage);
  transform: translateY(-1px);
}

.parallax-product-media {
  align-self: stretch;
  display: grid;
  place-items: center;
  position: sticky;
  top: calc(var(--header-height) + 2rem);
}

.parallax-product-media img {
  filter: drop-shadow(0 34px 60px rgba(32, 35, 34, 0.32));
  height: auto;
  max-height: min(72vh, 680px);
  max-width: min(100%, 520px);
  object-fit: contain;
  transform: translateY(clamp(-1rem, -2vw, -2rem));
  width: 100%;
}

@media (max-width: 900px) {
  .home-hero-content {
    align-items: stretch;
    flex-direction: column;
    justify-content: center;
  }

  .home-proof-strip {
    bottom: auto;
    left: auto;
    margin-top: 1rem;
    opacity: 1;
    position: static;
    right: auto;
    top: auto;
    width: 100%;
    z-index: 1;
  }

  .home-proof-grid {
    gap: 0.5rem;
  }

  .home-proof {
    background: rgba(32, 35, 34, 0.38);
    min-width: 0;
    padding: 0.55rem;
  }

  .home-proof span {
    font-size: 0.82rem;
  }

  .home-proof small {
    font-size: 0.6rem;
    line-height: 1.2;
  }
}

@media (max-width: 640px) {
  .home-proof-grid {
    gap: 0.45rem;
  }

  .home-proof {
    padding: 0.5rem;
  }

  .home-proof span {
    font-size: 0.78rem;
  }

  .home-proof small {
    font-size: 0.56rem;
  }
}

@media (max-width: 900px) {
  .footer-links {
    grid-template-columns: 1fr;
  }

  .home-shop-overlap {
    margin-top: -5rem;
    padding-left: 1rem;
    padding-right: 1rem;
  }

  .home-shop-heading {
    align-items: stretch;
  }

  .home-shop-cta {
    min-height: 46px;
    padding: 0.8rem 1rem;
    width: 100%;
  }

  .shop-hero {
    background-attachment: scroll;
    grid-template-columns: 1fr;
    min-height: auto;
  }

  .shop-hero-media {
    min-height: 320px;
  }

  .shop-grid-heading {
    grid-template-columns: 1fr;
  }

  .contact-hero {
    background-attachment: scroll;
    grid-template-columns: 1fr;
    min-height: auto;
  }

  .contact-hero-products {
    min-height: 320px;
  }

  .contact-info-band,
  .contact-brochure {
    grid-template-columns: 1fr;
  }

  .contact-social,
  .stockists-hero,
  .stockists-directory-heading,
  .stockists-list {
    grid-template-columns: 1fr;
  }

  .contact-info-band {
    grid-template-columns: 1fr;
  }

  .contact-info-band article {
    min-height: auto;
  }

  .stockists-hero,
  .stockists-map-card,
  .contact-social {
    background-attachment: scroll;
  }

  .contact-brochure {
    background-attachment: scroll;
  }

  .catalog-hero,
  .catalog-panel-backdrop,
  .contact-social,
  .stockists-hero {
    background-attachment: scroll;
  }

  .catalog-panel,
  .catalog-panel-content {
    min-height: auto;
  }

  .catalog-panel-content {
    grid-template-columns: 1fr;
    padding-bottom: 4rem;
    padding-top: 4rem;
  }

  .catalog-panel-product,
  .catalog-panel-card {
    animation: none;
    margin-top: 0;
    min-height: auto;
    position: relative;
    top: auto;
    transform: none;
  }

  .catalog-panel-product {
    min-height: 44svh;
  }

  .catalog-panel-product img {
    max-height: 45svh;
    max-width: min(84vw, 460px);
    transform: none;
  }

  .parallax-product {
    min-height: auto;
  }

  .parallax-product::before {
    background-attachment: scroll;
    background-image:
      linear-gradient(180deg, rgba(32, 35, 34, 0.64), rgba(32, 35, 34, 0.78)),
      var(--parallax-bg);
  }

  .parallax-product-inner {
    gap: 1.25rem;
    grid-template-columns: 1fr;
    min-height: auto;
    padding-bottom: 4rem;
    padding-top: 4rem;
  }

  .parallax-product-copy {
    max-width: none;
    order: 2;
  }

  .parallax-product-media {
    min-height: 42vh;
    order: 1;
    position: relative;
    top: auto;
  }

  .parallax-product-media img {
    max-height: 42vh;
    max-width: min(82vw, 420px);
    transform: none;
  }
}

@media (min-width: 768px) and (max-width: 900px) {
  .home-shop-heading {
    align-items: center;
  }

  .home-shop-cta {
    flex: 0 0 auto;
    max-width: 22rem;
    min-width: 15rem;
    width: auto;
  }
}

@media (prefers-reduced-motion: reduce) {
  .shop-hero-media img {
    animation: none;
    transform: none;
  }

  .contact-hero-products img {
    animation: none;
    transform: none;
  }

  .home-hero-image,
  .home-hero-copy,
  .home-hero-actions,
  .home-proof-strip,
  .home-story-copy,
  .home-story-media,
  .home-story-media img {
    animation: none;
    transform: none;
  }

  .catalog-hero,
  .catalog-panel-backdrop {
    background-attachment: scroll;
  }

  .catalog-panel-product,
  .catalog-panel-card,
  .catalog-panel-product img {
    animation: none;
    transform: none;
  }

  .catalog-panel-backdrop {
    animation: none;
    filter: none;
    transform: scale(1.04);
  }

  .parallax-product::before {
    background-attachment: scroll;
  }
}

