    transform: none;
  }
}

@media (max-width: 1100px) {
  .shop-hero {
    background-attachment: scroll;
    gap: clamp(0.8rem, 2.5vw, 1.25rem);
    grid-template-columns: 1fr;
    min-height: auto;
    overflow: visible;
    padding: clamp(1rem, 3.4vw, 1.8rem) clamp(1rem, 4vw, 2rem);
  }

  .shop-hero-copy {
    max-width: min(520px, 100%);
  }

