    font-size: clamp(1.45rem, 5.5vw, 2.45rem);
    max-width: 16ch;
  }

  .shop-hero-copy span {
    max-width: 30rem;
  }

  .shop-hero-media {
    display: none;
  }

  .shop-hero-media img {
    animation: none;
    max-height: min(16svh, 120px);
    transform: none;
  }

  .shop-hero-media img:nth-child(2),
  .shop-hero-media img:nth-child(3) {
    transform: none;
  }

  .shop-grid-heading,
  .contact-info-band,
  .contact-brochure,
  .contact-social {
    grid-template-columns: 1fr;
  }

  .contact-info-band article {
    min-height: auto;
  }

  .contact-brochure a {
    justify-self: start;
  }
}

@media (max-width: 1024px) {
  .contact-hero {
    background-attachment: scroll;
    gap: clamp(1.5rem, 5vw, 2.5rem);
    grid-template-columns: 1fr;
    min-height: auto;
    overflow: visible;
    padding: clamp(3rem, 8vw, 5rem) clamp(1.25rem, 5vw, 3rem);
  }

  .contact-hero-copy {
    max-width: min(760px, 100%);
  }

  .contact-hero-copy h1 {
    font-size: clamp(3rem, 10vw, 5rem);
