    grid-template-columns: repeat(3, minmax(0, 1fr));
    justify-self: stretch;
    margin-top: 0.5rem;
    max-width: none;
  }

  .contact-hero-products img,
  .contact-hero-products img:first-child,
  .contact-hero-products img:nth-child(2),
  .contact-hero-products img:nth-child(3) {
    max-height: min(30svh, 240px);
    width: 100%;
  }

  .contact-hero-products img:first-child {
    grid-column: auto;
  }
}

@media (max-width: 640px) {
