*/
:root {
  --header-height: 76px;
}

.header {
  background: rgba(253, 252, 248, 0.98);
  border-bottom: 1px solid rgba(32, 35, 34, 0.1);
  box-shadow: none;
  gap: clamp(0.8rem, 1.8vw, 1.8rem);
