  padding: 0 clamp(1rem, 4vw, 3rem);
}

.header--scrolled,
.header--scrolled:hover {
  background: rgba(253, 252, 248, 0.98);
  box-shadow: 0 14px 34px rgba(32, 35, 34, 0.07);
