/*
* --------------------------------------------------
* Home hero sample treatment
* --------------------------------------------------
*/
.home-hero-sample {
  align-items: center;
  background:
    radial-gradient(circle at 86% 16%, rgba(107, 127, 95, 0.12), transparent 30%),
    linear-gradient(100deg, #fffdf8 0%, #fbf5eb 58%, #efe2d1 100%);
  display: flex;
  isolation: isolate;
  margin-left: calc(50% - 50vw);
  margin-right: calc(50% - 50vw);
  min-height: min(690px, calc(100svh - var(--header-height) + 3rem));
  overflow: hidden;
  padding: clamp(2.4rem, 5.8vw, 5.5rem) 0
    clamp(6.2rem, 9vw, 8rem) clamp(1.25rem, 4vw, 4.25rem);
  position: relative;
}

.home-hero-sample::before {
  background: radial-gradient(
    ellipse 34% 92% at 13% 52%,
    rgba(255, 253, 248, 1) 0%,
    rgba(255, 253, 248, 0.96) 42%,
    rgba(255, 253, 248, 0.68) 56%,
    rgba(255, 253, 248, 0.18) 70%,
    rgba(255, 253, 248, 0) 84%
  );
  content: "";
  inset: 0;
  pointer-events: none;
  position: absolute;
  z-index: 2;
}

.home-hero-sample-content {
  align-items: center;
  display: grid;
  gap: clamp(1.5rem, 4vw, 4rem);
  grid-template-columns: minmax(280px, 42vw) 1fr;
  margin: 0;
  max-width: none;
  position: static;
  width: 100%;
  z-index: 2;
}

.home-hero-sample .home-hero-copy {
  max-width: 545px;
  position: relative;
  will-change: auto;
  z-index: 3;
}

.home-hero-eyebrow {
  color: #566d37;
  font-family: var(--font-sans);
  font-size: 0.72rem;
  font-weight: 800;
  letter-spacing: 0.22em;
  margin: 0;
  text-transform: uppercase;
}

.home-hero-sample .home-hero-copy h1 {
  color: var(--color-charcoal);
  font-family: var(--font-serif);
  font-size: clamp(2.45rem, 3.8vw, 3.8rem);
  font-weight: 600;
  line-height: 0.98;
  margin: 0.85rem 0 1rem;
  max-width: 17ch;
}

.home-hero-sample .home-hero-copy > p:not(.home-hero-eyebrow) {
  color: rgba(32, 35, 34, 0.72);
  font-size: clamp(0.96rem, 1.25vw, 1.08rem);
  line-height: 1.62;
  margin: 0;
  max-width: 460px;
}

.home-hero-sample .home-hero-actions {
  display: flex;
  flex-wrap: wrap;
  gap: 0.85rem;
  margin-top: 1.55rem;
  position: relative;
  will-change: auto;
  z-index: 2;
}

.home-hero-sample .home-primary-cta,
.home-hero-sample .home-secondary-cta {
  align-items: center;
  border-radius: 999px;
  display: inline-flex;
  font-size: 0.72rem;
  font-weight: 800;
  justify-content: center;
  letter-spacing: 0.12em;
  min-height: 48px;
  padding: 0 1.5rem;
  text-transform: uppercase;
  transition:
    background-color 160ms ease,
    border-color 160ms ease,
    color 160ms ease,
    transform 160ms ease;
}

.home-hero-sample .home-primary-cta {
  background: #566d37;
  border: 1px solid #566d37;
