@media (min-width: 768px) and (max-width: 880px) {
  .customizer-final-actions {
    gap: 0.55rem;
    grid-template-columns: minmax(4rem, 0.38fr) minmax(9.75rem, 1.12fr) minmax(10.25rem, 1fr);
  }

  .customizer-final-add,
  .customizer-final-shop {
    font-size: clamp(0.62rem, 1.18vw, 0.72rem);
    letter-spacing: 0.06em;
    padding-left: 0.65rem;
    padding-right: 0.65rem;
  }
}

/*
* --------------------------------------------------
* Product pages and mobile edge alignment
* --------------------------------------------------
*/
.product-page {
  background:
    radial-gradient(circle at 12% 8%, rgba(224, 215, 188, 0.36), transparent 28%),
    var(--color-cream);
}

.product-page #add-to-cart button[type="submit"] {
  background: #566d37 !important;
  border-radius: 999px !important;
  box-shadow: 0 14px 32px rgba(86, 109, 55, 0.24) !important;
  color: var(--color-off-white) !important;
}

.product-page #add-to-cart button[type="submit"]:hover {
  background: #7f936d !important;
}

.product-page .product-options-grid a,
.product-page .product-options-grid button {
  border-radius: 999px !important;
}

.product-page .product-options-grid .border-terracotta {
  background: rgba(86, 109, 55, 0.08) !important;
  border-color: #566d37 !important;
}

@media (min-width: 768px) {
  .product-page .hidden.md\:block > .max-w-6xl {
    background: rgba(224, 215, 188, 0.54);
    border: 1px solid rgba(160, 148, 110, 0.22);
    border-radius: 8px;
    box-shadow: 0 28px 74px rgba(32, 35, 34, 0.08);
    padding: clamp(1.25rem, 2.2vw, 2rem);
  }

  .product-page .sticky > div,
  .product-page .sticky img {
    border-radius: 8px;
  }
}

@media (max-width: 767px) {
  .product-page .md\:hidden {
    padding: 1rem;
  }

  .product-page .md\:hidden > div:first-child,
  .product-page .md\:hidden > div:first-child img {
    border-radius: 8px;
  }

  .product-page .md\:hidden > div:first-child {
    overflow: hidden;
  }

  .product-page .md\:hidden > div:nth-child(2) {
    background: rgba(224, 215, 188, 0.82);
    border: 1px solid rgba(160, 148, 110, 0.28);
    border-radius: 8px;
    margin-top: 1rem;
    padding: 1.15rem;
  }
}

@media (max-width: 640px) {
  body {
    border-left-width: 6px;
    border-right-width: 6px;
  }

  .home-hero-sample {
    margin-left: 0 !important;
    margin-right: 0 !important;
    padding-left: 1.05rem;
    padding-right: 1.05rem;
    width: 100%;
  }

  .home-hero-sample .home-hero-copy,
  .home-hero-sample .home-proof-strip {
    max-width: none;
  }

  .home-shop-overlap {
    padding-left: 0 !important;
    padding-right: 0 !important;
  }

  .home-shop-shell {
    margin-left: 0;
    margin-right: 0;
    width: 100%;
  }
}

/*
* --------------------------------------------------
* Home mobile scroll stability and proof-box parallax
* --------------------------------------------------
*/
@keyframes home-proof-soft-parallax {
  0% {
    opacity: 0.94;
    transform: translate3d(0, var(--home-proof-start, 10px), 0);
  }

  45% {
    opacity: 1;
    transform: translate3d(0, 0, 0);
  }

  100% {
    opacity: 0.96;
    transform: translate3d(0, var(--home-proof-end, -12px), 0);
  }
}

.home-hero-sample .home-proof:nth-child(1) {
  --home-proof-start: 7px;
  --home-proof-end: -8px;
}

.home-hero-sample .home-proof:nth-child(2) {
  --home-proof-start: 11px;
  --home-proof-end: -10px;
}

.home-hero-sample .home-proof:nth-child(3) {
  --home-proof-start: 9px;
  --home-proof-end: -13px;
}

@supports (animation-timeline: view()) {
  .home-hero-sample .home-proof {
    animation: home-proof-soft-parallax linear both;
    animation-range: entry -8% exit 92%;
    animation-timeline: view(block);
    will-change: transform, opacity;
  }
}

@media (max-width: 767px) {
  .home-story-copy,
  .home-story-media,
  .home-story-media img {
    opacity: 1 !important;
    transform: none !important;
  }
}

@media (max-width: 640px) {
  .home-hero-sample .home-proof:nth-child(1) {
    --home-proof-start: 4px;
    --home-proof-end: -5px;
  }

  .home-hero-sample .home-proof:nth-child(2) {
    --home-proof-start: 6px;
    --home-proof-end: -6px;
  }

  .home-hero-sample .home-proof:nth-child(3) {
    --home-proof-start: 5px;
    --home-proof-end: -7px;
  }
}
